"use client";

import * as React from "react";
import { useReducedMotion } from "motion/react";
import * as THREE from "three";

import { cn } from "@/lib/utils";
import { supportsWebGL, useHydrated, useMediaQuery } from "@/components/experience/experience-runtime";

export type FluidSurfaceProps = Omit<React.ComponentProps<"section">, "children"> & {
  label: string;
  src: string;
  alt: string;
  strength?: number;
  radius?: number;
  decay?: number;
  chromatic?: number;
  maxDpr?: number;
  children?: React.ReactNode;
  fallback?: React.ReactNode;
  canvasClassName?: string;
};

const VERTEX = /* glsl */ `varying vec2 vUv;void main(){vUv=uv;gl_Position=vec4(position,1.);}`;
const FRAGMENT = /* glsl */ `
  precision highp float; varying vec2 vUv; uniform sampler2D uTexture; uniform vec2 uResolution; uniform vec2 uImageSize; uniform vec4 uRipples[5]; uniform float uStrength; uniform float uRadius; uniform float uChromatic;
  vec2 coverUv(vec2 uv){float a=uResolution.x/max(1.,uResolution.y),b=uImageSize.x/max(1.,uImageSize.y);vec2 r=vec2(min(a/b,1.),min(b/a,1.));return(uv-.5)*r+.5;}
  void main(){vec2 aspect=vec2(uResolution.x/max(1.,uResolution.y),1.);vec2 displacement=vec2(0.);float highlight=0.;for(int i=0;i<5;i++){vec2 d=(vUv-uRipples[i].xy)*aspect;float dist=length(d);float age=uRipples[i].z;float amp=uRipples[i].w*exp(-age*2.2);float wave=sin(dist*42.-age*9.)*exp(-dist/max(.01,uRadius))*amp;displacement+=normalize(d+vec2(.0001))*wave*uStrength;highlight+=abs(wave)*.18;}vec2 uv=coverUv(vUv-displacement);vec2 ca=normalize(displacement+vec2(.0001))*uChromatic*min(1.,length(displacement)*35.);vec3 color;color.r=texture2D(uTexture,uv+ca).r;color.g=texture2D(uTexture,uv).g;color.b=texture2D(uTexture,uv-ca).b;color+=highlight;gl_FragColor=vec4(color,1.);}
`;

/** An image surface with dissipating pointer impulses; it preserves the native cursor. */
export function FluidSurface({ alt, canvasClassName, children, chromatic = .0014, className, decay = 1, fallback, label, maxDpr = 1.6, radius = .24, src, strength = .018, onPointerMove, ...props }: FluidSurfaceProps) {
  const rootRef = React.useRef<HTMLElement>(null), canvasRef = React.useRef<HTMLCanvasElement>(null), activeRef = React.useRef(true);
  const impulsesRef = React.useRef<Array<{ x: number; y: number; age: number; power: number }>>([]), lastPointerRef = React.useRef({ x: .5, y: .5, time: 0 });
  const hydrated = useHydrated(), reducedMotion = useReducedMotion(), coarse = useMediaQuery("(pointer: coarse)");
  const staticMode = hydrated && (Boolean(reducedMotion) || coarse);
  const [ready, setReady] = React.useState(false), [failed, setFailed] = React.useState(false);
  React.useEffect(() => {
    const root = rootRef.current, canvas = canvasRef.current; if (!root || !canvas || staticMode) return;
    if (!supportsWebGL()) { const timer = window.setTimeout(() => setFailed(true), 0); return () => window.clearTimeout(timer); }
    let disposed = false, frame = 0, previous = performance.now(); let texture: THREE.Texture | null = null;
    const renderer = new THREE.WebGLRenderer({ canvas, antialias: false, alpha: false, powerPreference: "high-performance" }); renderer.outputColorSpace = THREE.SRGBColorSpace; renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, maxDpr));
    const scene = new THREE.Scene(), camera = new THREE.Camera(), geometry = new THREE.PlaneGeometry(2, 2);
    const rippleVectors = Array.from({ length: 5 }, () => new THREE.Vector4(.5, .5, 99, 0));
    const uniforms = { uTexture: { value: new THREE.Texture() }, uResolution: { value: new THREE.Vector2(1, 1) }, uImageSize: { value: new THREE.Vector2(1, 1) }, uRipples: { value: rippleVectors }, uStrength: { value: strength }, uRadius: { value: radius }, uChromatic: { value: chromatic } };
    const material = new THREE.ShaderMaterial({ vertexShader: VERTEX, fragmentShader: FRAGMENT, uniforms, depthTest: false, depthWrite: false }); scene.add(new THREE.Mesh(geometry, material));
    const resize = () => { const width = Math.max(1, root.clientWidth), height = Math.max(1, root.clientHeight); renderer.setSize(width, height, false); uniforms.uResolution.value.set(width, height); renderer.render(scene, camera); };
    const resizeObserver = new ResizeObserver(resize); resizeObserver.observe(root); const intersectionObserver = new IntersectionObserver(([entry]) => { activeRef.current = Boolean(entry?.isIntersecting); }, { rootMargin: "20% 0px" }); intersectionObserver.observe(root);
    const contextLost = (event: Event) => { event.preventDefault(); if (!disposed) setFailed(true); }; canvas.addEventListener("webglcontextlost", contextLost);
    const render = (time: number) => { if (disposed) return; const delta = Math.min(.05, Math.max(.001, (time - previous) / 1000)); previous = time; if (activeRef.current && document.visibilityState === "visible") { impulsesRef.current.forEach((impulse) => { impulse.age += delta * decay; }); impulsesRef.current = impulsesRef.current.filter((impulse) => impulse.age < 2.6).slice(-5); rippleVectors.forEach((vector, index) => { const impulse = impulsesRef.current[index]; vector.set(impulse?.x ?? .5, impulse?.y ?? .5, impulse?.age ?? 99, impulse?.power ?? 0); }); renderer.render(scene, camera); } frame = requestAnimationFrame(render); };
    new THREE.TextureLoader().load(src, (loaded) => { if (disposed) { loaded.dispose(); return; } texture = loaded; texture.colorSpace = THREE.SRGBColorSpace; const image = loaded.image as { width?: number; height?: number }; uniforms.uTexture.value = loaded; uniforms.uImageSize.value.set(image.width ?? 1, image.height ?? 1); resize(); setReady(true); frame = requestAnimationFrame(render); }, undefined, () => { if (!disposed) setFailed(true); });
    return () => { disposed = true; cancelAnimationFrame(frame); resizeObserver.disconnect(); intersectionObserver.disconnect(); canvas.removeEventListener("webglcontextlost", contextLost); texture?.dispose(); geometry.dispose(); material.dispose(); renderer.dispose(); };
  }, [chromatic, decay, maxDpr, radius, src, staticMode, strength]);
  const handlePointerMove = (event: React.PointerEvent<HTMLElement>) => { if (event.pointerType !== "touch") { const now = performance.now(), rect = event.currentTarget.getBoundingClientRect(), x = (event.clientX - rect.left) / Math.max(1, rect.width), y = 1 - (event.clientY - rect.top) / Math.max(1, rect.height), previous = lastPointerRef.current; if (now - previous.time > 42) { const velocity = Math.min(1, Math.hypot(x - previous.x, y - previous.y) * 18 + .18); impulsesRef.current.push({ x, y, age: 0, power: velocity }); lastPointerRef.current = { x, y, time: now }; } } onPointerMove?.(event); };
  const posterStyle = { backgroundImage: `url("${src.replaceAll('"', '%22')}")` };
  return <section ref={rootRef} aria-label={label} data-fluid-surface data-ready={ready || undefined} className={cn("relative isolate overflow-hidden bg-black", className)} onPointerMove={handlePointerMove} {...props}><span className="sr-only">{alt}</span><div aria-hidden className={cn("absolute inset-0 -z-20 bg-cover bg-center", ready && !failed && !staticMode ? "opacity-0" : "opacity-100")} style={posterStyle} /><canvas ref={canvasRef} aria-hidden className={cn("absolute inset-0 -z-10 size-full transition-opacity duration-500", ready && !failed && !staticMode ? "opacity-100" : "opacity-0", canvasClassName)} />{(failed || staticMode) && fallback ? <div className="absolute inset-0 -z-10">{fallback}</div> : null}{children}</section>;
}

"use client";

import * as React from "react";

const subscribeToHydration = () => () => undefined;

export function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

export function useMediaQuery(query: string, serverValue = false) {
  const subscribe = React.useCallback(
    (onChange: () => void) => {
      const media = window.matchMedia(query);
      media.addEventListener("change", onChange);
      return () => media.removeEventListener("change", onChange);
    },
    [query],
  );
  const getSnapshot = React.useCallback(() => window.matchMedia(query).matches, [query]);
  return React.useSyncExternalStore(subscribe, getSnapshot, () => serverValue);
}

/**
 * Hydration-safe reduced-motion preference: false on the server and during
 * hydration, then live. Replaces the repeated `mounted && useReducedMotion()`
 * pattern.
 */
export function usePrefersReducedMotion() {
  return useMediaQuery("(prefers-reduced-motion: reduce)");
}

/** True on touch-first devices; use to swap pointer effects for static or rail modes. */
export function useCoarsePointer() {
  return useMediaQuery("(pointer: coarse)");
}

/** True only when a hover-capable precise pointer is present. */
export function useFinePointer() {
  return useMediaQuery("(hover: hover) and (pointer: fine)");
}

export function clamp01(value: number) {
  return Math.min(1, Math.max(0, value));
}

export function mix(from: number, to: number, amount: number) {
  return from + (to - from) * amount;
}

export function damp(current: number, target: number, smoothing: number, deltaSeconds: number) {
  return mix(current, target, 1 - Math.exp(-Math.max(0.01, smoothing) * deltaSeconds));
}

/** Returns the frames sorted by `at`, reusing the input when it is already ordered. */
export function sortKeyframes<T extends { at: number }>(frames: T[]): T[] {
  for (let index = 1; index < frames.length; index += 1) {
    if (frames[index - 1]!.at > frames[index]!.at) {
      return [...frames].sort((left, right) => left.at - right.at);
    }
  }
  return frames;
}

export function resolveKeyframes<T extends { at: number }>(
  frames: T[],
  progress: number,
): { from: T; to: T; mix: number } {
  if (frames.length === 0) throw new Error("Experience keyframes cannot be empty.");
  const sorted = sortKeyframes(frames);
  if (progress <= sorted[0]!.at) return { from: sorted[0]!, to: sorted[0]!, mix: 0 };
  for (let index = 0; index < sorted.length - 1; index += 1) {
    const from = sorted[index]!;
    const to = sorted[index + 1]!;
    if (progress <= to.at) {
      const span = Math.max(0.0001, to.at - from.at);
      return { from, to, mix: clamp01((progress - from.at) / span) };
    }
  }
  const final = sorted.at(-1)!;
  return { from: final, to: final, mix: 0 };
}

export function supportsWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(
      canvas.getContext("webgl2", { failIfMajorPerformanceCaveat: true })
      || canvas.getContext("webgl", { failIfMajorPerformanceCaveat: true }),
    );
  } catch {
    return false;
  }
}
